1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isMainItem = (type: string): boolean => MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
17	
18	const isComponent = (type: string): boolean => !isMainItem(type);
19	
20	const isKnownType = (type: string): boolean =>
21	  isMainItem(type) || KNOWN_COMPONENT_TYPES.has(type);
22	
23	const CURSED_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	
27	const calculateItemSurcharges = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
28	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
29	  const curseSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
30	  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
31	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
32	    : 0;
33	  return curseSurcharge + enchantmentSurcharge;
34	};
35	
36	const calculateComponentGroupPremium = (count: number): number =>
37	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
38	
39	const INSURANCE_VALUES: Record<string, number> = {
40	  sword: 1000,
41	  amulet: 600,
42	  staff: 800,
43	  potion: 400,
44	};
45	const COMPONENT_INSURANCE_VALUE = 250;
46	const DEDUCTIBLE = 100;
47	
48	const getInsuranceValue = (type: string): number =>
49	  INSURANCE_VALUES[type] ?? COMPONENT_INSURANCE_VALUE;
50	
51	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
52	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
53	
54	const calculateClaimPayout = (
55	  damages: { itemType: string; amount: number }[],
56	  remainingCap: number,
57	  policyItems: any[],
58	): { payout: number; remainingCap: number } => {
59	  let totalPayout = 0;
60	  for (const damage of damages) {
61	    const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
62	    const enchantment = policyItem?.enchantment ?? 0;
63	    let reimbursement = damage.amount;
64	    if (enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
65	      reimbursement = damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE;
66	    }
67	    totalPayout += Math.max(0, reimbursement - DEDUCTIBLE);
68	  }
69	  if (totalPayout > remainingCap) {
70	    totalPayout = remainingCap;
71	  }
