84	    }
85	  }
86	
87	  let policyBasePremium = 0;
88	  let itemSurcharges = 0;
89	
90	  const componentCounts: Record<string, number> = {};
91	  for (const item of items) {
92	    if (isComponent(item.type)) {
93	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
94	    } else {
