104	  const policyModifierRate = FIRST_INSURANCE_RATE
105	    - (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0)
106	    - (isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0);
107	  const policyModifiers = policyBasePremium * policyModifierRate;
108	
109	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
